// ─── FILTRAR Y DECIDIR ACCIÓN POR INACTIVIDAD ───
// Entrada: items del nodo PostgreSQL
// Salida: items con acción 'avisar' o 'cerrar'
// Luego un IF node bifurca según accion === 'avisar'

const ITEMS = $input.all();
const RESULT = [];

const DIAS = ['domingo', 'lunes', 'martes', 'miércoles', 'jueves', 'viernes', 'sábado'];

for (const item of ITEMS) {
  const json = item.json;

  // 1. Parsear schedule_text
  let scheduleText = {};
  try {
    scheduleText = typeof json.schedule_text === 'string'
      ? JSON.parse(json.schedule_text)
      : json.schedule_text;
  } catch (e) {
    scheduleText = {};
  }

  // 2. Verificar horario laboral
  const ahora = new Date();
  const diaSemana = DIAS[ahora.getDay()];
  const horaActual = ahora.getHours() * 60 + ahora.getMinutes();

  const horarioHoy = scheduleText[diaSemana];
  let dentroDeHorario = false;

  if (horarioHoy && horarioHoy.length > 0) {
    for (const bloque of horarioHoy) {
      if (bloque.desde && bloque.hasta) {
        const [hDesde, mDesde] = bloque.desde.split(':').map(Number);
        const [hHasta, mHasta] = bloque.hasta.split(':').map(Number);
        const inicio = hDesde * 60 + mDesde;
        const fin = hHasta * 60 + mHasta;
        if (horaActual >= inicio && horaActual <= fin) {
          dentroDeHorario = true;
          break;
        }
      }
    }
  }

  if (!dentroDeHorario) continue;

  // 3. Revisar último mensaje del assistant
  let ultimoMensaje = '';
  try {
    const messages = typeof json.messages === 'string'
      ? JSON.parse(json.messages)
      : json.messages;
    if (Array.isArray(messages) && messages.length > 0) {
      for (let i = messages.length - 1; i >= 0; i--) {
        if (messages[i].role === 'assistant') {
          ultimoMensaje = messages[i].content || messages[i].text || '';
          break;
        }
      }
    }
  } catch (e) {}

  // 4. Detectar cierre de conversación
  const patronesCierre = ['CITA_CONFIRMADA', 'GESTIONAR_CITA', 'fuera de horario', 'vuelve mañana', 'gracias por escribir'];
  if (patronesCierre.some(p => ultimoMensaje.includes(p))) continue;

  // 5. Decidir acción
  if (json.inactividad_estado === null || json.inactividad_estado === undefined || json.inactividad_estado === '') {
    RESULT.push({ json: { accion: 'avisar', numero: json.numero, business_id: json.business_id, instance: json.instance } });
  } else if (json.inactividad_estado === 'avisado') {
    RESULT.push({ json: { accion: 'cerrar', numero: json.numero, business_id: json.business_id } });
  }
}

return RESULT;

